// Kanban Board Backend State Management
// Exposes window.kanbanAPI for frontend integration

const STORAGE_KEY = 'kanban-board';

// Initialize default board state
const DEFAULT_BOARD = {
  columns: [
    { id: 'todo', title: 'Todo', cards: [] },
    { id: 'doing', title: 'Doing', cards: [] },
    { id: 'done', title: 'Done', cards: [] }
  ]
};

// Subscribers for state changes
let subscribers = [];

// Load persisted state or use default
function loadBoard() {
  const stored = localStorage.getItem(STORAGE_KEY);
  return stored ? JSON.parse(stored) : DEFAULT_BOARD;
}

// Save board to localStorage
function saveBoard(board) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(board));
}

// Current board state
let board = loadBoard();

// Notify all subscribers of state change
function notifySubscribers() {
  subscribers.forEach(cb => cb(board));
}

// Generate unique ID for cards
function generateId() {
  return 'card-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);
}

// Add a new card to a column
function addCard(columnId, title) {
  const column = board.columns.find(col => col.id === columnId);
  if (!column || !title.trim()) {
    return false;
  }
  column.cards.push({
    id: generateId(),
    title: title.trim()
  });
  saveBoard(board);
  notifySubscribers();
  return true;
}

// Delete a card from a column
function deleteCard(columnId, cardId) {
  const column = board.columns.find(col => col.id === columnId);
  if (!column) {
    return false;
  }
  const cardIndex = column.cards.findIndex(card => card.id === cardId);
  if (cardIndex === -1) {
    return false;
  }
  column.cards.splice(cardIndex, 1);
  saveBoard(board);
  notifySubscribers();
  return true;
}

// Move a card to another column
function moveCard(fromColumnId, toColumnId, cardId) {
  const fromColumn = board.columns.find(col => col.id === fromColumnId);
  const toColumn = board.columns.find(col => col.id === toColumnId);

  if (!fromColumn || !toColumn) {
    return false;
  }

  const cardIndex = fromColumn.cards.findIndex(card => card.id === cardId);
  if (cardIndex === -1) {
    return false;
  }

  const card = fromColumn.cards.splice(cardIndex, 1)[0];
  toColumn.cards.push(card);
  saveBoard(board);
  notifySubscribers();
  return true;
}

// Get current board state
function getBoard() {
  return JSON.parse(JSON.stringify(board));
}

// Subscribe to board changes
function subscribe(callback) {
  if (typeof callback === 'function') {
    subscribers.push(callback);
    // Immediately call with current state
    callback(board);
  }
}

// Expose API
window.kanbanAPI = {
  addCard,
  deleteCard,
  moveCard,
  getBoard,
  subscribe
};
